import{_ as e,o as l,c as a,a2 as r}from"./chunks/framework.Pywvta2k.js";const x=JSON.parse('{"title":"傅青主女科","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/04-明清/06-傅青主女科（傅青主）.md","filePath":"tcm-data/04-明清/06-傅青主女科（傅青主）.md","lastUpdated":1781084559000}'),n={name:"tcm-data/04-明清/06-傅青主女科（傅青主）.md"};function d(o,t,s,i,g,h){return l(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="傅青主女科" tabindex="-1">傅青主女科 <a class="header-anchor" href="#傅青主女科" aria-label="Permalink to &quot;傅青主女科&quot;">​</a></h1><blockquote><p>傅山（1607-1684年），山西阳曲人 明末清初大儒，中医妇科学集大成者 代表作：《傅青主女科》《傅青主男科》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：字青主，号真山、朱衣道人</li><li><strong>生平</strong>：明末遗民，拒绝清朝征召，以行医为生</li><li><strong>学术地位</strong>：继《金匮要略》妇人三篇后，<strong>中医妇科学的最高峰</strong></li><li><strong>特点</strong>：<strong>方简量重，效如桴鼓</strong>——每方不过8-12味药，但剂量精准</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-调经重气血" tabindex="-1">1. 调经重气血 <a class="header-anchor" href="#_1-调经重气血" aria-label="Permalink to &quot;1. 调经重气血&quot;">​</a></h3><blockquote><p><strong>「夫经水者，乃气血之化也。」</strong><strong>「经水先期者，火旺也。然火旺不可专责之火，因水旺而火亦旺。」</strong></p></blockquote><p>傅青主对月经病的辨证极为精细：</p><table tabindex="0"><thead><tr><th style="text-align:left;">月经病</th><th style="text-align:left;">傅青主辨证</th><th style="text-align:left;">治法</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>先期量多</strong></td><td style="text-align:left;">血热</td><td style="text-align:left;">清经散（清火为主）</td></tr><tr><td style="text-align:left;"><strong>先期量少</strong></td><td style="text-align:left;">肾中火旺而水亏</td><td style="text-align:left;">两地汤（滋阴为主）</td></tr><tr><td style="text-align:left;"><strong>后期量少</strong></td><td style="text-align:left;">血寒</td><td style="text-align:left;">温经摄血汤</td></tr><tr><td style="text-align:left;"><strong>先后无定期</strong></td><td style="text-align:left;">肝郁</td><td style="text-align:left;">定经汤</td></tr></tbody></table><h3 id="_2-带下分五色" tabindex="-1">2. 带下分五色 <a class="header-anchor" href="#_2-带下分五色" aria-label="Permalink to &quot;2. 带下分五色&quot;">​</a></h3><blockquote><p><strong>「带下俱是湿证。」</strong></p></blockquote><p>傅青主将带下按五色治疗：</p><table tabindex="0"><thead><tr><th style="text-align:left;">带色</th><th style="text-align:left;">病机</th><th style="text-align:left;">代表方</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>白带</strong></td><td style="text-align:left;">脾虚湿盛</td><td style="text-align:left;">完带汤</td></tr><tr><td style="text-align:left;"><strong>青带</strong></td><td style="text-align:left;">肝经湿热</td><td style="text-align:left;">加减逍遥散</td></tr><tr><td style="text-align:left;"><strong>黄带</strong></td><td style="text-align:left;">湿热下注</td><td style="text-align:left;">易黄汤</td></tr><tr><td style="text-align:left;"><strong>黑带</strong></td><td style="text-align:left;">火热极盛</td><td style="text-align:left;">利火汤</td></tr><tr><td style="text-align:left;"><strong>赤带</strong></td><td style="text-align:left;">湿热瘀血</td><td style="text-align:left;">清肝止淋汤</td></tr></tbody></table><h3 id="_3-种子重肝肾" tabindex="-1">3. 种子重肝肾 <a class="header-anchor" href="#_3-种子重肝肾" aria-label="Permalink to &quot;3. 种子重肝肾&quot;">​</a></h3><blockquote><p><strong>「夫种子，男精女血。」</strong></p></blockquote><p>傅青主认为不孕的核心在肝肾，男女各分十证，各有专方。</p><h3 id="_4-血崩论" tabindex="-1">4. 血崩论 <a class="header-anchor" href="#_4-血崩论" aria-label="Permalink to &quot;4. 血崩论&quot;">​</a></h3><blockquote><p><strong>「血崩不止，当分阴阳。」</strong></p></blockquote><p>傅青主将血崩分为：气虚血崩、郁结血崩、血热血崩、闪跌血崩、年老血崩等，各有专方。</p><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;">⭐ <strong>完带汤</strong></td><td style="text-align:left;">白术、山药、人参、白芍、车前子、苍术、甘草、陈皮、黑芥穗、柴胡</td><td style="text-align:left;"><strong>白带（参考方）</strong></td></tr><tr><td style="text-align:left;"><strong>清经散</strong></td><td style="text-align:left;">丹皮、地骨皮、白芍、青蒿、黄柏、茯苓</td><td style="text-align:left;">月经先期（血热）</td></tr><tr><td style="text-align:left;"><strong>两地汤</strong></td><td style="text-align:left;">生地、地骨皮、玄参、麦冬、阿胶、白芍</td><td style="text-align:left;">月经先期（阴虚）</td></tr><tr><td style="text-align:left;"><strong>定经汤</strong></td><td style="text-align:left;">当归、白芍、熟地、柴胡、山药、菟丝子、茯苓、荆芥穗</td><td style="text-align:left;">月经先后无定期</td></tr><tr><td style="text-align:left;"><strong>易黄汤</strong></td><td style="text-align:left;">山药、芡实、黄柏、车前子、白果</td><td style="text-align:left;">黄带</td></tr><tr><td style="text-align:left;"><strong>生化汤</strong></td><td style="text-align:left;">当归、川芎、桃仁、炮姜、炙甘草</td><td style="text-align:left;">产后恶露不行</td></tr><tr><td style="text-align:left;"><strong>温经摄血汤</strong></td><td style="text-align:left;">熟地、白芍、川芎、五味子、续断、肉桂、白术、柴胡</td><td style="text-align:left;">月经后期</td></tr></tbody></table><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「夫经水者，乃气血之化也。」</strong></p></blockquote><blockquote><p><strong>「带下俱是湿证。」</strong></p></blockquote><blockquote><p><strong>「种子，男精女血。」</strong></p></blockquote><blockquote><p><strong>「血崩不止，当分阴阳。」</strong></p></blockquote><blockquote><p><strong>「夫产后，大补气血为先，虽有他证，以末治之。」</strong></p></blockquote><hr><h2 id="五、对该女性患者的指导" tabindex="-1">五、对该女性患者的指导 <a class="header-anchor" href="#五、对该女性患者的指导" aria-label="Permalink to &quot;五、对该女性患者的指导&quot;">​</a></h2><p><strong>患者（女）症状</strong>：月经先期（28天→23-25天）、白带量多偏黄</p><table tabindex="0"><thead><tr><th style="text-align:left;">症状</th><th style="text-align:left;">傅青主辨证</th><th style="text-align:left;">建议方</th></tr></thead><tbody><tr><td style="text-align:left;">月经先期+量正常+烦躁</td><td style="text-align:left;">肝郁血热</td><td style="text-align:left;">清经散或定经汤</td></tr><tr><td style="text-align:left;">白带量多偏白</td><td style="text-align:left;">脾虚湿盛</td><td style="text-align:left;">完带汤</td></tr><tr><td style="text-align:left;">经期腰凉+怕冷</td><td style="text-align:left;">肾虚寒凝</td><td style="text-align:left;">温经摄血汤加减</td></tr></tbody></table><p>**患者处方&quot;加减黄芽地魄汤&quot;**中已包含：</p><ul><li>当归、白芍、熟地 → 养血调经（傅青主思路）</li><li>柴胡 → 疏肝解郁</li><li>杜仲 → 补肾强腰</li><li>白术 → 健脾止带</li></ul><hr><p><em>本条目为精简框架版。可扩展至傅青主女科全书逐方解析、与《金匮》妇人三篇的对比等专题。</em></p>',39)])])}const y=e(n,[["render",d]]);export{x as __pageData,y as default};
